import sys

def main():
    n = int(raw_input())
    arr = [int(i) for i in raw_input().split()]
    max_value = max(arr)
    min_value = min(arr)
    max_index = arr.index(max_value)
    min_index = arr.index(min_value)
    if max_value == 0:
        print 0
    elif max_value < 0:
        print 1
